Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega/v6.json",
  "autosize": {"type": "fit", "contains": "padding"},
  "background": "white",
  "padding": 5,
  "style": "cell",
  "data": [
    {"name": "dataset"},
    {
      "name": "patient_check",
      "source": "dataset",
      "transform": [
        {"type": "filter", "expr": "datum.PatientID != null"},
        {"type": "aggregate", "groupby": ["PatientID"]}
      ]
    },
    {
      "name": "data_0",
      "source": "dataset",
      "transform": [
        {"type": "filter", "expr": "isSinglePatient"},
        {"type": "filter", "expr": "datum.PatientID != null"},
        {"type": "formula", "expr": "toDate(datum.Start)", "as": "StartDate"},
        {"type": "formula", "expr": "toDate(datum.End)", "as": "EndDate"},
        {
          "type": "formula",
          "expr": "split(datum.Lane,''|'')[1] == ''Track'' ? split(datum.Lane,''|'')[2] : null",
          "as": "Discipline"
        },
        {
          "type": "formula",
          "expr": "datum.Discipline == ''PT'' ? ''01'' : datum.Discipline == ''OT'' ? ''02'' : datum.Discipline == ''ST'' ? ''03'' : ''99''",
          "as": "DisciplineOrder"
        },
        {
          "type": "formula",
          "expr": "split(datum.Lane,''|'')[1] == ''PLOS'' ? split(datum.Lane,''|'')[2] : null",
          "as": "PLOSCategory"
        },
        {
          "type": "formula",
          "expr": "datum.PLOSCategory == ''Nursing Restorative'' ? ''01'' : datum.PLOSCategory == ''Rehab Tech'' ? ''02'' : datum.PLOSCategory == ''Screens'' ? ''03'' : datum.PLOSCategory == ''Wellness'' ? ''04'' : ''99''",
          "as": "PLOSOrder"
        },
        {
          "type": "formula",
          "expr": "split(datum.Lane,''|'')[1] == ''Track'' ? ''06|Track|'' + datum.DisciplineOrder + ''|'' + datum.Discipline : split(datum.Lane,''|'')[1] == ''PLOS'' ? ''07|PLOS|'' + datum.PLOSOrder + ''|'' + datum.PLOSCategory : datum.Lane",
          "as": "LaneSortKey"
        },
        {
          "type": "formula",
          "expr": "datum.EventType == ''Payer'' ? (indexof(datum.Detail, '') '') >= 0 ? substring(datum.Detail, indexof(datum.Detail, '') '') + 2) : datum.Detail) : datum.Detail",
          "as": "DetailClean"
        },
        {
          "type": "formula",
          "expr": "split(datum.LaneSortKey,''|'')[1] == ''Track'' ? split(datum.LaneSortKey,''|'')[3] : split(datum.LaneSortKey,''|'')[1] == ''PLOS'' ? split(datum.LaneSortKey,''|'')[3] : split(datum.LaneSortKey,''|'')[1] == ''Discharge'' ? ''Discharge'' : join(slice(split(datum.LaneSortKey,''|''),1),''|'')",
          "as": "LaneLabel"
        },
        {
          "type": "formula",
          "expr": "datum.StartDate != null && datum.EndDate != null ? floor((datum.EndDate - datum.StartDate) / 86400000) : null",
          "as": "DurationDays"
        },
        {
          "type": "formula",
          "expr": "datum.EventType == ''Case'' ? datum.Detail : null",
          "as": "DischargeTo"
        },
        {
          "type": "filter",
          "expr": "datum.EventType != ''Residence'' || datum.Detail != null"
        },
        {
          "type": "filter",
          "expr": "datum.EventType != ''Payer'' || datum.DetailClean != null"
        }
      ]
    },
    {
      "name": "lane_list",
      "source": "data_0",
      "transform": [
        {
          "type": "aggregate",
          "groupby": ["LaneSortKey"],
          "ops": ["count"],
          "fields": ["LaneSortKey"],
          "as": ["_count"]
        },
        {
          "type": "formula",
          "expr": "split(datum.LaneSortKey,''|'')[1] == ''Track'' ? '' '' + split(datum.LaneSortKey,''|'')[3] : split(datum.LaneSortKey,''|'')[1] == ''PLOS'' ? split(datum.LaneSortKey,''|'')[3] : split(datum.LaneSortKey,''|'')[1] == ''Discharge'' ? ''Discharge'' : split(datum.LaneSortKey,''|'')[1] == ''Residence'' ? ''Residence'' : split(datum.LaneSortKey,''|'')[1] == ''Payer'' ? ''Payer'' : split(datum.LaneSortKey,''|'')[1] == ''Case'' ? ''Case'' : split(datum.LaneSortKey,''|'')[1] == ''Visit'' ? ''Visit'' : join(slice(split(datum.LaneSortKey,''|''),1),''|'')",
          "as": "LaneLabel"
        },
        {
          "type": "formula",
          "expr": "split(datum.LaneSortKey,''|'')[1] == ''Case'' || split(datum.LaneSortKey,''|'')[1] == ''Track'' ? barbellLaneWeight : (split(datum.LaneSortKey,''|'')[1] == ''Residence'' || split(datum.LaneSortKey,''|'')[1] == ''Payer'' || split(datum.LaneSortKey,''|'')[1] == ''PLOS'' || split(datum.LaneSortKey,''|'')[1] == ''Discharge'' ? compactLaneWeight : 1)",
          "as": "LaneWeight"
        },
        {
          "type": "collect",
          "sort": {"field": "LaneSortKey", "order": "ascending"}
        },
        {
          "type": "window",
          "sort": {"field": "LaneSortKey", "order": "ascending"},
          "ops": ["sum"],
          "fields": ["LaneWeight"],
          "as": ["LaneY1"],
          "frame": [null, 0]
        },
        {
          "type": "formula",
          "expr": "datum.LaneY1 - datum.LaneWeight",
          "as": "LaneY0"
        },
        {
          "type": "window",
          "sort": {"field": "LaneSortKey", "order": "ascending"},
          "ops": ["row_number"],
          "fields": [null],
          "as": ["_row_index"]
        },
        {
          "type": "formula",
          "expr": "datum.LaneY0 + laneGap * (datum._row_index - 1)",
          "as": "LaneY0"
        },
        {
          "type": "formula",
          "expr": "datum.LaneY1 + laneGap * (datum._row_index - 1)",
          "as": "LaneY1"
        },
        {
          "type": "formula",
          "expr": "(datum.LaneY0 + datum.LaneY1) / 2",
          "as": "LaneYC"
        },
        {"type": "extent", "field": "LaneY1", "signal": "yExtent"}
      ]
    },
    {
      "name": "lane_separators",
      "source": "lane_list",
      "transform": [
        {"type": "filter", "expr": "datum._row_index < length(data(''lane_list''))"},
        {"type": "window", "sort": {"field": "LaneSortKey", "order": "ascending"}, "ops": ["lead"], "fields": ["LaneSortKey"], "as": ["NextLaneSortKey"]},
        {"type": "filter", "expr": "!(split(datum.LaneSortKey,''|'')[1] == ''Case'' && split(datum.NextLaneSortKey,''|'')[1] == ''Discharge'') && !(split(datum.LaneSortKey,''|'')[1] == ''Track'' && split(datum.NextLaneSortKey,''|'')[1] == ''Track'')"},
        {"type": "formula", "expr": "datum.LaneY1 + laneGap/2", "as": "LaneSeparatorY"}
      ]
    },
    {
      "name": "data_1",
      "source": "data_0",
      "transform": [
        {
          "type": "filter",
          "expr": "datum.StartDate != null && datum.EndDate != null && (datum.EndDate >= datum.StartDate) && datum.EventType != ''Visit'' && datum.EventType != ''PLOS'' && datum.EventType != ''Residence'' && datum.EventType != ''Payer'' && datum.EventType != ''Discharge''"
        }
      ]
    },
    {
      "name": "data_2",
      "source": "data_1",
      "transform": [
        {
          "type": "filter",
          "expr": "(isDate(datum[\"StartDate\"]) || (isValid(datum[\"StartDate\"]) && isFinite(+datum[\"StartDate\"])))"
        },
        {"type": "lookup", "from": "lane_list", "key": "LaneSortKey", "fields": ["LaneSortKey"], "values": ["LaneY0", "LaneY1", "LaneYC"], "as": ["LaneY0", "LaneY1", "LaneYC"]}
      ]
    },
    {
      "name": "data_3",
      "source": "data_0",
      "transform": [
        {
          "type": "filter",
          "expr": "datum.StartDate != null && datum.EndDate != null && datum.EndDate != datum.StartDate && datum.EventType == ''Residence''"
        }
      ]
    },
    {
      "name": "data_4",
      "source": "data_3",
      "transform": [
        {
          "type": "filter",
          "expr": "(isDate(datum[\"StartDate\"]) || (isValid(datum[\"StartDate\"]) && isFinite(+datum[\"StartDate\"])))"
        },
        {"type": "lookup", "from": "lane_list", "key": "LaneSortKey", "fields": ["LaneSortKey"], "values": ["LaneY0", "LaneY1", "LaneYC"], "as": ["LaneY0", "LaneY1", "LaneYC"]}
      ]
    },
    {
      "name": "data_5",
      "source": "data_0",
      "transform": [
        {
          "type": "filter",
          "expr": "datum.StartDate != null && datum.EndDate != null && datum.EndDate != datum.StartDate && datum.EventType == ''Payer''"
        }
      ]
    },
    {
      "name": "data_6",
      "source": "data_5",
      "transform": [
        {
          "type": "filter",
          "expr": "(isDate(datum[\"StartDate\"]) || (isValid(datum[\"StartDate\"]) && isFinite(+datum[\"StartDate\"])))"
        },
        {"type": "lookup", "from": "lane_list", "key": "LaneSortKey", "fields": ["LaneSortKey"], "values": ["LaneY0", "LaneY1", "LaneYC"], "as": ["LaneY0", "LaneY1", "LaneYC"]}
      ]
    },
    {
      "name": "data_7",
      "source": "data_0",
      "transform": [
        {
          "type": "filter",
          "expr": "datum.StartDate != null && datum.EventType == ''Discharge''"
        }
      ]
    },
    {
      "name": "data_8",
      "source": "data_7",
      "transform": [
        {
          "type": "filter",
          "expr": "(isDate(datum[\"StartDate\"]) || (isValid(datum[\"StartDate\"]) && isFinite(+datum[\"StartDate\"])))"
        },
        {"type": "lookup", "from": "lane_list", "key": "LaneSortKey", "fields": ["LaneSortKey"], "values": ["LaneY0", "LaneY1", "LaneYC"], "as": ["LaneY0", "LaneY1", "LaneYC"]}
      ]
    },
    {
      "name": "data_9",
      "source": "data_0",
      "transform": [
        {
          "type": "filter",
          "expr": "datum.StartDate != null && datum.EventType == ''Visit''"
        },
        {"type": "formula", "expr": "''Skilled Visit''", "as": "VisitLegend"}
      ]
    },
    {
      "name": "data_10",
      "source": "data_9",
      "transform": [
        {
          "type": "filter",
          "expr": "(isDate(datum[\"StartDate\"]) || (isValid(datum[\"StartDate\"]) && isFinite(+datum[\"StartDate\"])))"
        },
        {"type": "lookup", "from": "lane_list", "key": "LaneSortKey", "fields": ["LaneSortKey"], "values": ["LaneY0", "LaneY1", "LaneYC"], "as": ["LaneY0", "LaneY1", "LaneYC"]}
      ]
    },
    {
      "name": "data_11",
      "source": "data_0",
      "transform": [
        {
          "type": "filter",
          "expr": "datum.StartDate != null && datum.EventType == ''PLOS''"
        }
      ]
    },
    {
      "name": "data_12",
      "source": "data_11",
      "transform": [
        {
          "type": "filter",
          "expr": "(isDate(datum[\"StartDate\"]) || (isValid(datum[\"StartDate\"]) && isFinite(+datum[\"StartDate\"])))"
        },
        {"type": "lookup", "from": "lane_list", "key": "LaneSortKey", "fields": ["LaneSortKey"], "values": ["LaneY0", "LaneY1", "LaneYC"], "as": ["LaneY0", "LaneY1", "LaneYC"]}
      ]
    },
    {
      "name": "data_13",
      "source": "data_0",
      "transform": [
        {"type": "filter", "expr": "datum.PatientID != null"},
        {
          "type": "formula",
          "expr": "datum[''Timeline[AdmitLevel]''] != null ? datum[''Timeline[AdmitLevel]''] : (datum[''Admit Level''] != null ? datum[''Admit Level''] : datum.AdmitLevel)",
          "as": "AdmitLevelVal"
        },
        {
          "type": "formula",
          "expr": "datum[''Timeline[DischargeLevel]''] != null ? datum[''Timeline[DischargeLevel]''] : (datum[''Discharge Level''] != null ? datum[''Discharge Level''] : datum.DischargeLevel)",
          "as": "DischargeLevelVal"
        },
        {
          "type": "filter",
          "expr": "(datum.EventType == ''Case'' || datum.EventType == ''Track'') && datum.StartDate != null && datum.EndDate != null && datum.AdmitLevelVal != null && datum.DischargeLevelVal != null"
        },
        {
          "type": "formula",
          "expr": "datum.AdmitLevelVal <= 1.5 ? datum.AdmitLevelVal * 100 : datum.AdmitLevelVal",
          "as": "AdmitPct"
        },
        {
          "type": "formula",
          "expr": "datum.DischargeLevelVal <= 1.5 ? datum.DischargeLevelVal * 100 : datum.DischargeLevelVal",
          "as": "DischargePct"
        },
        {
          "type": "fold",
          "fields": ["AdmitPct", "DischargePct"],
          "as": ["Point", "LevelPct"]
        },
        {
          "type": "formula",
          "expr": "datum.Point == ''AdmitPct'' ? ''Start'' : ''End''",
          "as": "PointLabel"
        },
        {
          "type": "formula",
          "expr": "datum.Point == ''AdmitPct'' ? datum.StartDate : datum.EndDate",
          "as": "OutcomeDate"
        },
        {
          "type": "formula",
          "expr": "datum.Point == ''AdmitPct'' ? 0 : 1",
          "as": "PointOrder"
        },
        {"type": "lookup", "from": "lane_list", "key": "LaneSortKey", "fields": ["LaneSortKey"], "values": ["LaneY0", "LaneY1", "LaneYC"], "as": ["LaneY0", "LaneY1", "LaneYC"]}
      ]
    },
    {
      "name": "data_14",
      "source": "data_13",
      "transform": [
        {
          "type": "filter",
          "expr": "(isDate(datum[\"OutcomeDate\"]) || (isValid(datum[\"OutcomeDate\"]) && isFinite(+datum[\"OutcomeDate\"])))"
        }
      ]
    }
  ],
  "signals": [
    {
      "name": "width",
      "update": "isFinite(containerSize()[0]) ? containerSize()[0] : 300"
    },
    {
      "name": "height",
      "update": "isFinite(containerSize()[1]) ? containerSize()[1] : 300"
    },
    {
      "name": "barbellLaneHeight",
      "value": 20
    },
    {
      "name": "barbellLaneWeight",
      "value": 2
    },
    {
      "name": "compactLaneWeight",
      "value": 0.5
    },
    {
      "name": "laneGap",
      "value": 0.15
    },
    {
      "name": "yDomain",
      "update": "length(data(''lane_list'')) > 0 ? [0, yExtent[1]] : [0, 1]"
    },
    {
      "name": "isSinglePatient",
      "update": "length(data(''patient_check'')) == 1"
    },
    {
      "name": "emptyStateMessage",
      "update": "length(data(''patient_check'')) == 0 ? ''No patient data available'' : length(data(''patient_check'')) > 1 ? ''Select a single patient to view the timeline'' : ''''"
    }
  ],
  "marks": [
    {
      "name": "lane_labels_marks",
      "type": "text",
      "from": {"data": "lane_list"},
      "encode": {
        "update": {
          "x": {"value": 0},
          "y": {"scale": "y", "field": "LaneYC"},
          "dx": {"value": -6},
          "text": {"field": "LaneLabel"},
          "align": {"value": "right"},
          "baseline": {"value": "middle"},
          "fontSize": {"value": 11},
          "fill": {"value": "#333333"}
        }
      }
    },
    {
      "name": "lane_separators_marks",
      "type": "rule",
      "from": {"data": "lane_separators"},
      "encode": {
        "update": {
          "x": {"value": 0},
          "x2": {"signal": "width"},
          "y": {"scale": "y", "field": "LaneSeparatorY"},
          "stroke": {"value": "#e0e0e0"},
          "strokeWidth": {"value": 1}
        }
      }
    },
    {
      "name": "spans_main_marks",
      "type": "rect",
      "style": ["bar"],
      "from": {"data": "data_2"},
      "encode": {
        "update": {
          "strokeWidth": {"value": 1.4},
          "cornerRadius": {"value": 2},
          "fill": {"value": "#0c436a"},
          "stroke": {"value": "#0c436a"},
          "opacity": [
            {"test": "datum.LaneGroup == ''06|Track''", "value": 0.28},
            {"value": 0.85}
          ],
          "tooltip": {
            "signal": "{\"Event\": isValid(datum[\"EventType\"]) ? isArray(datum[\"EventType\"]) ? join(datum[\"EventType\"], ''\\n'') : datum[\"EventType\"] : \"\"+datum[\"EventType\"], \"Lane\": isValid(datum[\"LaneLabel\"]) ? isArray(datum[\"LaneLabel\"]) ? join(datum[\"LaneLabel\"], ''\\n'') : datum[\"LaneLabel\"] : \"\"+datum[\"LaneLabel\"], \"Detail\": isValid(datum[\"Detail\"]) ? isArray(datum[\"Detail\"]) ? join(datum[\"Detail\"], ''\\n'') : datum[\"Detail\"] : \"\"+datum[\"Detail\"], \"Start\": timeFormat(datum[\"StartDate\"], \"%b %d, %Y\"), \"End\": timeFormat(datum[\"EndDate\"], \"%b %d, %Y\"), \"Days\": format(datum[\"DurationDays\"], \"\"), \"ItemID\": isValid(datum[\"ItemID\"]) ? isArray(datum[\"ItemID\"]) ? join(datum[\"ItemID\"], ''\\n'') : datum[\"ItemID\"] : \"\"+datum[\"ItemID\"]}"
          },
          "ariaRoleDescription": {"value": "bar"},
          "description": {
            "signal": "\"StartDate: \" + (timeFormat(datum[\"StartDate\"], \"%b %d, %Y\")) + \"; LaneSortKey: \" + (isValid(datum[\"LaneSortKey\"]) ? isArray(datum[\"LaneSortKey\"]) ? join(datum[\"LaneSortKey\"], '' '') : datum[\"LaneSortKey\"] : \"\"+datum[\"LaneSortKey\"]) + \"; EndDate: \" + (timeFormat(datum[\"EndDate\"], \"%b %d, %Y\")) + \"; Event: \" + (isValid(datum[\"EventType\"]) ? isArray(datum[\"EventType\"]) ? join(datum[\"EventType\"], '' '') : datum[\"EventType\"] : \"\"+datum[\"EventType\"]) + \"; Lane: \" + (isValid(datum[\"LaneLabel\"]) ? isArray(datum[\"LaneLabel\"]) ? join(datum[\"LaneLabel\"], '' '') : datum[\"LaneLabel\"] : \"\"+datum[\"LaneLabel\"]) + \"; Discharge To: \" + (isValid(datum[\"DischargeTo\"]) ? isArray(datum[\"DischargeTo\"]) ? join(datum[\"DischargeTo\"], '' '') : datum[\"DischargeTo\"] : \"\"+datum[\"DischargeTo\"]) + \"; Detail: \" + (isValid(datum[\"Detail\"]) ? isArray(datum[\"Detail\"]) ? join(datum[\"Detail\"], '' '') : datum[\"Detail\"] : \"\"+datum[\"Detail\"]) + \"; Start: \" + (timeFormat(datum[\"StartDate\"], \"%b %d, %Y\")) + \"; End: \" + (timeFormat(datum[\"EndDate\"], \"%b %d, %Y\")) + \"; Days: \" + (format(datum[\"DurationDays\"], \"\")) + \"; ItemID: \" + (isValid(datum[\"ItemID\"]) ? isArray(datum[\"ItemID\"]) ? join(datum[\"ItemID\"], '' '') : datum[\"ItemID\"] : \"\"+datum[\"ItemID\"])"
          },
          "x": {"scale": "x", "field": "StartDate"},
          "x2": {"scale": "x", "field": "EndDate"},
          "y": {"scale": "y", "field": "LaneY0"},
          "y2": {"scale": "y", "field": "LaneY1"}
        }
      }
    },
    {
      "name": "residence_spans_marks",
      "type": "rect",
      "style": ["bar"],
      "from": {"data": "data_4"},
      "encode": {
        "update": {
          "strokeWidth": {"value": 1.4},
          "cornerRadius": {"value": 2},
          "fill": {"scale": "residence_spans_color", "field": "Detail"},
          "stroke": {"scale": "residence_spans_stroke", "field": "Detail"},
          "opacity": {"value": 0.85},
          "tooltip": {
            "signal": "{\"Event\": isValid(datum[\"EventType\"]) ? isArray(datum[\"EventType\"]) ? join(datum[\"EventType\"], ''\\n'') : datum[\"EventType\"] : \"\"+datum[\"EventType\"], \"Residence\": isValid(datum[\"Detail\"]) ? isArray(datum[\"Detail\"]) ? join(datum[\"Detail\"], ''\\n'') : datum[\"Detail\"] : \"\"+datum[\"Detail\"], \"Start\": timeFormat(datum[\"StartDate\"], \"%b %d, %Y\"), \"End\": timeFormat(datum[\"EndDate\"], \"%b %d, %Y\"), \"Days\": format(datum[\"DurationDays\"], \"\"), \"ItemID\": isValid(datum[\"ItemID\"]) ? isArray(datum[\"ItemID\"]) ? join(datum[\"ItemID\"], ''\\n'') : datum[\"ItemID\"] : \"\"+datum[\"ItemID\"]}"
          },
          "ariaRoleDescription": {"value": "bar"},
          "description": {
            "signal": "\"StartDate: \" + (timeFormat(datum[\"StartDate\"], \"%b %d, %Y\")) + \"; LaneSortKey: \" + (isValid(datum[\"LaneSortKey\"]) ? isArray(datum[\"LaneSortKey\"]) ? join(datum[\"LaneSortKey\"], '' '') : datum[\"LaneSortKey\"] : \"\"+datum[\"LaneSortKey\"]) + \"; EndDate: \" + (timeFormat(datum[\"EndDate\"], \"%b %d, %Y\")) + \"; Detail: \" + (isValid(datum[\"Detail\"]) ? isArray(datum[\"Detail\"]) ? join(datum[\"Detail\"], '' '') : datum[\"Detail\"] : \"\"+datum[\"Detail\"]) + \"; Event: \" + (isValid(datum[\"EventType\"]) ? isArray(datum[\"EventType\"]) ? join(datum[\"EventType\"], '' '') : datum[\"EventType\"] : \"\"+datum[\"EventType\"]) + \"; Residence: \" + (isValid(datum[\"Detail\"]) ? isArray(datum[\"Detail\"]) ? join(datum[\"Detail\"], '' '') : datum[\"Detail\"] : \"\"+datum[\"Detail\"]) + \"; Start: \" + (timeFormat(datum[\"StartDate\"], \"%b %d, %Y\")) + \"; End: \" + (timeFormat(datum[\"EndDate\"], \"%b %d, %Y\")) + \"; Days: \" + (format(datum[\"DurationDays\"], \"\")) + \"; ItemID: \" + (isValid(datum[\"ItemID\"]) ? isArray(datum[\"ItemID\"]) ? join(datum[\"ItemID\"], '' '') : datum[\"ItemID\"] : \"\"+datum[\"ItemID\"])"
          },
          "x": {"scale": "x", "field": "StartDate"},
          "x2": {"scale": "x", "field": "EndDate"},
          "y": {"scale": "y", "field": "LaneY0"},
          "y2": {"scale": "y", "field": "LaneY1"}
        }
      }
    },
    {
      "name": "residence_labels_marks",
      "type": "text",
      "from": {"data": "data_4"},
      "encode": {
        "update": {
          "x": {"scale": "x", "field": "StartDate"},
          "y": {"scale": "y", "field": "LaneYC"},
          "dx": {"value": 4},
          "text": {"field": "Detail"},
          "align": {"value": "left"},
          "baseline": {"value": "middle"},
